744	export function stairPlanThree(
745	  stair: Extract<Element, { kind: 'stair' }>,
746	  elementsById?: Record<string, Element>,
747	  wireDoc?: StairPlanWireDocOverlays | null,
748	): THREE.Group | null {
749	  if (stair.shape === 'spiral') {
750	    return spiralStairPlanGroup(stair);
751	  }
752	  if (stair.shape === 'sketch') {
753	    return sketchStairPlanGroup(stair);
754	  }
755	  const sx = stair.runStartMm.xMm / 1000;
756	  const sz = stair.runStartMm.yMm / 1000;
757	  const ex = stair.runEndMm.xMm / 1000;
758	  const ez = stair.runEndMm.yMm / 1000;
759	  const dx = ex - sx;
760	  const dz = ez - sz;
761	  const len = Math.max(1e-6, Math.hypot(dx, dz));
762	  const uxDir = dx / len;
763	  const uzDir = dz / len;
764	  const px = -uzDir * (stair.widthMm / 2000);
765	
766	  const pz = uxDir * (stair.widthMm / 2000);
767	
768	  const g = new THREE.Group();
769	
770	  const outline = [
771	    new THREE.Vector3(sx + px, PLAN_Y + 0.012, sz + pz),
772	
773	    new THREE.Vector3(ex + px, PLAN_Y + 0.012, ez + pz),
774	
775	    new THREE.Vector3(ex - px, PLAN_Y + 0.012, ez - pz),
776	
777	    new THREE.Vector3(sx - px, PLAN_Y + 0.012, sz - pz),
778	
779	    new THREE.Vector3(sx + px, PLAN_Y + 0.012, sz + pz),
780	  ];
781	
782	  g.add(
783	    new THREE.Line(
784	      new THREE.BufferGeometry().setFromPoints(outline),
785	      new THREE.LineBasicMaterial({
786	        color: getPlanPalette().dimAlt,
787	        transparent: true,
788	        opacity: 0.92,
789	      }),
790	    ),
791	  );
792	
793	  const nSteps = computeStairPlanRiserCount(stair, elementsById);
794	  const stepLen = len / nSteps;
795	
796	  const runOffX = uxDir * stepLen;
797	
798	  const runOffZ = uzDir * stepLen;
799	
800	  for (let i = 0; i <= nSteps; i++) {
801	    const t = sx + uxDir * stepLen * i;
802	
803	    const w = sz + uzDir * stepLen * i;
804	
805	    const p1 = new THREE.Vector3(t + px, PLAN_Y + 0.018, w + pz);
806	
807	    const p2 = new THREE.Vector3(t - px, PLAN_Y + 0.018, w - pz);
808	
809	    g.add(
810	      new THREE.Line(
811	        new THREE.BufferGeometry().setFromPoints([p1, p2]),
812	        new THREE.LineBasicMaterial({
813	          color: getPlanPalette().hairline,
814	          transparent: true,
815	          opacity: 0.55,
816	        }),
817	      ),
818	    );
819	
820	    if (i < nSteps) {
821	      const c1 = new THREE.Vector3(
822	        t + runOffX + px * 0.15,
823	        PLAN_Y + 0.018,
824	        w + runOffZ + pz * 0.15,
825	      );
826	
827	      const c2 = new THREE.Vector3(
828	        t + runOffX - px * 0.15,
829	        PLAN_Y + 0.018,
830	        w + runOffZ - pz * 0.15,
831	      );
832	
833	      g.add(
834	        new THREE.Line(
835	          new THREE.BufferGeometry().setFromPoints([c1, c2]),
836	          new THREE.LineBasicMaterial({
837	            color: getPlanPalette().hairlineStrong,
838	            transparent: true,
839	            opacity: 0.45,
840	          }),
841	        ),
842	      );
843	    }
844	  }
845	
846	  if (wireDoc) {
847	    const mx = (sx + ex) * 0.5;
848	    const mz = (sz + ez) * 0.5;
849	    const yDoc = PLAN_Y + 0.024;
850	    let bx = uxDir;
851	    let bz = uzDir;
852	    if (
853	      wireDoc.runBearingDegCcFromPlanX !== undefined &&
854	      Number.isFinite(wireDoc.runBearingDegCcFromPlanX)
855	    ) {
856	      const rad = (wireDoc.runBearingDegCcFromPlanX * Math.PI) / 180;
857	      bx = Math.cos(rad);
858	      bz = Math.sin(rad);
859	    }
860	    const alen = Math.min(len, 0.55) * 0.35;
861	    const tip = new THREE.Vector3(mx + bx * alen * 0.45, yDoc, mz + bz * alen * 0.45);
862	    const tail = new THREE.Vector3(mx - bx * alen * 0.55, yDoc, mz - bz * alen * 0.55);
863	    const arrMat = new THREE.LineBasicMaterial({
864	      color: getPlanPalette().dimLine,
865	      transparent: true,
866	      opacity: 0.88,
867	    });
868	    g.add(new THREE.Line(new THREE.BufferGeometry().setFromPoints([tail, tip]), arrMat));
869	    const perpX = -bz * 0.06;
870	    const perpZ = bx * 0.06;
871	    const b1 = new THREE.Vector3(tip.x - bx * 0.12 + perpX, yDoc, tip.z - bz * 0.12 + perpZ);
872	    const b2 = new THREE.Vector3(tip.x - bx * 0.12 - perpX, yDoc, tip.z - bz * 0.12 - perpZ);
873	    g.add(new THREE.Line(new THREE.BufferGeometry().setFromPoints([tip, b1]), arrMat));
874	    g.add(new THREE.Line(new THREE.BufferGeometry().setFromPoints([tip, b2]), arrMat));
875	
876	    const ph = wireDoc.stairDocumentationPlaceholders_v0;
877	    if (ph?.bottomLandingFootprintBoundsMm && ph?.topLandingFootprintBoundsMm) {
878	      const yLand = PLAN_Y + 0.021;
879	      const landMat = new THREE.LineBasicMaterial({
880	        color: getPlanPalette().windowFillBackline,
881	        transparent: true,
882	        opacity: 0.52,
883	      });
884	      for (const b of [ph.bottomLandingFootprintBoundsMm, ph.topLandingFootprintBoundsMm]) {
885	        const x0 = b.minXmMm / 1000;
886	        const x1 = b.maxXmMm / 1000;
887	        const z0 = b.minYmMm / 1000;
888	        const z1 = b.maxYmMm / 1000;
889	        const ring = [
890	          new THREE.Vector3(x0, yLand, z0),
891	          new THREE.Vector3(x1, yLand, z0),
892	          new THREE.Vector3(x1, yLand, z1),
893	          new THREE.Vector3(x0, yLand, z1),
894	          new THREE.Vector3(x0, yLand, z0),
895	        ];
896	        g.add(new THREE.Line(new THREE.BufferGeometry().setFromPoints(ring), landMat));
897	      }
898	    }
899	
900	    const ann =
901	      wireDoc.stairPlanSectionDocumentationLabel?.trim() || wireDoc.planUpDownLabel?.trim();
902	    if (ann) {
903	      const lx = sx + uxDir * Math.min(len * 0.2, 0.35);
904	      const lz = sz + uzDir * Math.min(len * 0.2, 0.35);
905	      const tagScale = wireDoc.stairPlanSectionDocumentationLabel ? 0.62 : 0.85;
906	      g.add(planAnnotationLabelSprite(lx, lz, ann, stair.id, tagScale));
907	    }
908	
909	    if (wireDoc.stairPlanBreakVisibilityToken === 'cutSplitsSpan') {
910	      const zx = mx - bz * (stair.widthMm / 2000) * 0.35;
911	      const zz = mz + bx * (stair.widthMm / 2000) * 0.35;
912	      const zig = 0.04;
913	      const p0 = new THREE.Vector3(zx - bx * zig, PLAN_Y + 0.026, zz - bz * zig);
914	      const p1 = new THREE.Vector3(zx + bx * zig, PLAN_Y + 0.026, zz + bz * zig);
915	      const p2 = new THREE.Vector3(zx + bx * zig * 2, PLAN_Y + 0.026, zz + bz * zig * 2);
916	      const brkMat = new THREE.LineBasicMaterial({
917	        color: getPlanPalette().dimWitness,
918	        transparent: true,
919	        opacity: 0.7,
920	      });
921	      g.add(new THREE.Line(new THREE.BufferGeometry().setFromPoints([p0, p1]), brkMat));
922	      g.add(new THREE.Line(new THREE.BufferGeometry().setFromPoints([p1, p2]), brkMat));
923	    }
924	  }
925	
926	  g.userData.bimPickId = stair.id;
927	
928	  return g;
929	}
