40	export function planWallMesh(
41	  wall: Extract<Element, { kind: 'wall' }>,
42	  selectedId?: string,
43	  lineWeightScale = 1,
44	  elementsById?: Record<string, Element>,
45	  detailLevel: PlanDetailLevel = 'medium',
46	): THREE.Object3D {
47	  const { lenM: len, nx, nz } = segmentDir(wall);
48	
49	  const sx = ux(wall.start.xMm);
50	
51	  const sz = uz(wall.start.yMm);
52	
53	  const angle = Math.atan2(nz, nx);
54	
55	  const thick = THREE.MathUtils.clamp((wall.thicknessMm * lineWeightScale) / 1000, 0.02, 1.8);
56	
57	  const locFrac = planLocationLineOffsetFrac(wall.locationLine ?? 'wall-centerline');
58	  const perpX = -nz * locFrac * thick;
59	  const perpZ = nx * locFrac * thick;
60	
61	  const geom = new THREE.BoxGeometry(len, PLAN_WALL_CENTER_SLICE_HEIGHT_M, thick);
62	
63	  const mat = new THREE.MeshStandardMaterial({
64	    roughness: 0.82,
65	
66	    metalness: 0.02,
67	
68	    color: (() => {
69	      const p = getPlanPalette();
70	      return wall.id === selectedId ? p.wallSelected : p.wallFill;
71	    })(),
72	  });
73	
74	  const mesh = new THREE.Mesh(geom, mat);
75	
76	  mesh.position.set(sx + (nx * len) / 2 + perpX, PLAN_Y, sz + (nz * len) / 2 + perpZ);
77	
78	  mesh.rotation.y = -angle;
79	
80	  mesh.userData.bimPickId = wall.id;
81	
82	  // FL-08 + VIE-01: when the wall has a wall_type, overlay layer boundary
83	  // lines — but gate by detail level (coarse drops them entirely so the wall
84	  // reads as a single solid bar; medium shows just the core boundaries; fine
85	  // shows the full layer stack).
86	  if (wall.wallTypeId && detailLevel !== 'coarse') {
87	    const lines = buildPlanWallLayerLines(wall, len, sx, sz, nx, nz, elementsById, detailLevel);
88	    if (lines) {
89	      const group = new THREE.Group();
90	      group.userData.bimPickId = wall.id;
91	      group.add(mesh);
92	      group.add(lines);
93	      return group;
94	    }
95	  }
96	
97	  // KRN-09: per-cell curtain-panel fills overlaid on the plan box.
98	  if (wall.isCurtainWall && wall.curtainPanelOverrides) {
99	    const fills = buildCurtainPanelPlanFills(wall, len, sx, sz, nx, nz, thick);
100	    if (fills) {
101	      const group = new THREE.Group();
102	      group.userData.bimPickId = wall.id;
103	      group.add(mesh);
104	      group.add(fills);
105	      return group;
106	    }
107	  }
108	
109	  return mesh;
