112	/**
113	 * KRN-09 — overlay short rectangular fills on a curtain wall's plan symbol,
114	 * one per overridden grid cell. Empty = white, system = registered material
115	 * colour, family_instance = placeholder magenta. Cells without overrides
116	 * leave the underlying wall-fill colour visible.
117	 */
118	function buildCurtainPanelPlanFills(
119	  wall: Extract<Element, { kind: 'wall' }>,
120	  lenM: number,
121	  sx: number,
122	  sz: number,
123	  nx: number,
124	  nz: number,
125	  thickM: number,
126	): THREE.Group | null {
127	  const overrides = wall.curtainPanelOverrides;
128	  if (!overrides) return null;
129	  const vCount =
130	    wall.curtainWallVCount != null
131	      ? Math.max(1, wall.curtainWallVCount)
132	      : Math.max(1, Math.round(wall.heightMm > 0 ? lenM / 1.5 : 1));
133	  const cellLenM = lenM / vCount;
134	  // The plan symbol is a flat rectangle; for each overridden cell we stack
135	  // a thin coloured tile slightly above the wall fill so it reads in the
136	  // top-down view without z-fighting.
137	  const group = new THREE.Group();
138	  group.userData.bimPickId = wall.id;
139	  group.userData.curtainPanelFills = true;
140	  let added = 0;
141	  for (let v = 0; v < vCount; v++) {
142	    // The plan symbol collapses the H grid into a single strip — we colour
143	    // the cell stripe based on the override at row 0 if present, falling
144	    // back to any other row that has an override (so a wood panel shows
145	    // up regardless of which floor it sits on in the V/H grid).
146	    const cellOverride =
147	      overrides[curtainGridCellId(v, 0)] ??
148	      Object.entries(overrides).find(([k]) => k.startsWith(`v${v}h`))?.[1];
149	    if (!cellOverride) continue;
150	    let colorHex: string;
151	    if (cellOverride.kind === 'empty') colorHex = '#ffffff';
152	    else if (cellOverride.kind === 'family_instance') colorHex = '#ff66cc';
153	    else colorHex = materialBaseColor(cellOverride.materialKey);
154	    const tileGeom = new THREE.PlaneGeometry(cellLenM * 0.9, thickM * 0.9);
155	    const tileMat = new THREE.MeshBasicMaterial({
156	      color: colorHex,
157	      transparent: cellOverride.kind === 'empty',
158	      opacity: cellOverride.kind === 'empty' ? 0.6 : 1.0,
159	      side: THREE.DoubleSide,
160	    });
161	    const tile = new THREE.Mesh(tileGeom, tileMat);
162	    const tCenter = (v + 0.5) / vCount;
163	    const cxMid = sx + nx * lenM * tCenter;
164	    const czMid = sz + nz * lenM * tCenter;
165	    tile.position.set(cxMid, PLAN_Y + 0.01, czMid);
166	    tile.rotation.x = -Math.PI / 2;
167	    tile.rotation.z = -Math.atan2(nz, nx);
168	    tile.userData.bimPickId = wall.id;
169	    tile.userData.curtainCellId = curtainGridCellId(v, 0);
170	    tile.userData.curtainPanelKind = cellOverride.kind;
171	    group.add(tile);
172	    added += 1;
173	  }
174	  return added > 0 ? group : null;
175	}
